    `source_record_id` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in subscriber.subscription_change',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in subscriber.subscription_change',
    `zuora_amendment_reference` STRING COMMENT 'The unique identifier of the Zuora subscription amendment record that represents this change. Enables reconciliation with the billing system of record. | Column zuora_amendment_reference (STRING) in subscriber.subscription_change',
    CONSTRAINT pk_subscription_change PRIMARY KEY(`subscription_change_id`)
) COMMENT 'Audit trail of all plan changes, upgrades, downgrades, pauses, reinstatements, and promotional offer redemptions on a subscribers subscription. Captures previous plan, new plan, change type (upgrade, downgrade, pause, reactivate, add-on attach, add-on detach, offer redemption), effective date, change channel, proration amount, applied discount, offer reference, redemption status, and Zuora amendment reference. Enables subscription lifecycle analysis, promotion effectiveness tracking, and revenue reconciliation. | Unity Catalog table: media_broadcasting_ecm.subscriber.subscription_change D2C streaming lifecycle entity supporting subscriber+subscription+entitlement+playback_session+churn_event+offer flows.';

