    `redemption_code` STRING COMMENT 'The unique promotional code or voucher code entered by the subscriber at the time of redemption. Used for tracking and validation. | Column redemption_code (STRING) in subscriber.offer_redemption. Valid values are `^[A-Z0-9]{6,20}$`',
    `redemption_device_type` STRING COMMENT 'The type of device used by the subscriber to redeem the offer. Supports device-specific campaign optimization and user experience analysis. | Column redemption_device_type (STRING) in subscriber.offer_redemption. Valid values are `desktop|mobile|tablet|smart_tv|streaming_device|game_console`',
    `redemption_ip_address` STRING COMMENT 'The IP address from which the redemption request originated. Used for fraud detection and geographic analysis. May be considered Personally Identifiable Information (PII) under General Data Protection Regulation (GDPR). | Column redemption_ip_address (STRING) in subscriber.offer_redemption. Valid values are `^(?:[0-9]{1,3}.){3}[0-9]{1,3}$|^([0-9a-fA-F]{1,4}:){7}[0-9a-fA-F]{1,4}$`',
    `redemption_status` STRING COMMENT 'Current lifecycle status of the offer redemption. Tracks whether the redemption was successfully applied, expired before use, reversed due to policy violation, or rejected due to eligibility failure. | Column redemption_status (STRING) in subscriber.offer_redemption. Valid values are `applied|expired|reversed|pending|rejected|cancelled`',
    `redemption_timestamp` TIMESTAMP COMMENT 'The exact date and time when the subscriber successfully redeemed the promotional offer. Represents the business event time of redemption. | Column redemption_timestamp (TIMESTAMP) in subscriber.offer_redemption',
    `revenue_impact_amount` DECIMAL(18,2) COMMENT 'The estimated impact on revenue resulting from this offer redemption. Negative values represent revenue reduction due to discounts; positive values may represent incremental revenue from new subscriptions or upgrades. | Column revenue_impact_amount (DECIMAL(15,2)) in subscriber.offer_redemption',
    `reversal_reason` STRING COMMENT 'Explanation of why the offer redemption was reversed. Common reasons include fraud detection, policy violation, subscriber request, or billing dispute. Null if not reversed. | Column reversal_reason (STRING) in subscriber.offer_redemption',
    `reversal_timestamp` TIMESTAMP COMMENT 'The date and time when the offer redemption was reversed or cancelled. Null if the redemption remains active. Used for chargeback and refund reconciliation. | Column reversal_timestamp (TIMESTAMP) in subscriber.offer_redemption',
    `source_record_id` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in subscriber.offer_redemption',
    `terms_accepted_flag` BOOLEAN COMMENT 'Indicates whether the subscriber explicitly accepted the terms and conditions associated with the promotional offer at the time of redemption. Required for compliance and dispute resolution. | Column terms_accepted_flag (BOOLEAN) in subscriber.offer_redemption',
    `terms_version` STRING COMMENT 'The version identifier of the offer terms and conditions that the subscriber agreed to at redemption. Format: v1.0, v2.1, etc. Used for legal audit trails. | Column terms_version (STRING) in subscriber.offer_redemption. Valid values are `^v[0-9]+.[0-9]+$`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in subscriber.offer_redemption',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this offer redemption record was last modified. Used for audit trail and change tracking. | Column updated_timestamp (TIMESTAMP) in subscriber.offer_redemption',
    `zuora_subscription_number` STRING COMMENT 'The subscription identifier in the Zuora billing system that was created or modified as a result of this offer redemption. Used for billing reconciliation and revenue recognition. | Column zuora_subscription_number (STRING) in subscriber.offer_redemption. Valid values are `^[A-Z0-9-]{8,30}$`',
    CONSTRAINT pk_offer_redemption PRIMARY KEY(`offer_redemption_id`)
) COMMENT 'Transactional record of a subscriber redeeming a promotional offer or discount code. Captures subscriber reference, offer reference, redemption timestamp, redemption channel, applied discount amount, resulting subscription plan, and redemption status (applied, expired, reversed). Enables promotion effectiveness tracking and revenue impact reconciliation. | Unity Catalog table: media_broadcasting_ecm.subscriber.offer_redemption';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`subscriber`.`subscriber_consent_record` (
    `subscriber_consent_record_id` BIGINT COMMENT 'Unique identifier for the subscriber consent record. Primary key for the immutable audit trail of consent events. | Column subscriber_consent_record_id (BIGINT) in subscriber.subscriber_consent_record',
