CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`subscriber`.`csat_survey` (
    `csat_survey_id` BIGINT COMMENT 'Primary key for CSAT survey',
    `subscriber_id` BIGINT COMMENT 'FK to subscriber',
    `support_case_id` BIGINT COMMENT 'FK to support case if applicable',
    `agent_rating` STRING COMMENT 'Rating of support agent (1-5)',
    `ces_score` BIGINT COMMENT '',
    `completed_timestamp` TIMESTAMP COMMENT 'When survey was completed',
    `created_at` TIMESTAMP COMMENT '',
    `created_timestamp` TIMESTAMP COMMENT 'Record creation timestamp',
    `csat_score` BIGINT COMMENT '',
    `customer_effort_score` STRING COMMENT 'Customer Effort Score (1-7)',
    `feedback_text` STRING COMMENT '',
    `follow_up_completed_flag` BOOLEAN COMMENT 'Whether follow-up was completed',
    `follow_up_requested_flag` BOOLEAN COMMENT '',
    `follow_up_required_flag` BOOLEAN COMMENT 'Whether follow-up is required',
    `nps_category` STRING COMMENT 'NPS category (detractor, passive, promoter)',
    `nps_score` STRING COMMENT 'Net Promoter Score (0-10)',
    `overall_satisfaction_score` STRING COMMENT 'Overall satisfaction score (1-5 or 1-10)',
    `resolution_rating` STRING COMMENT 'Rating of issue resolution (1-5)',
    `responded_at` TIMESTAMP COMMENT '',
    `response_time_rating` STRING COMMENT 'Rating of response time (1-5)',
    `sent_at` TIMESTAMP COMMENT '',
    `sent_timestamp` TIMESTAMP COMMENT 'When survey was sent',
