    `survey_status` STRING COMMENT 'Status (sent, opened, completed, expired)',
    `survey_type` STRING COMMENT 'Type (post_contact, periodic, nps, ces)',
    `updated_at` TIMESTAMP COMMENT '',
    `updated_timestamp` TIMESTAMP COMMENT 'Record last update timestamp',
    `verbatim_feedback` STRING COMMENT 'Open-ended feedback text',
    `would_recommend_flag` BOOLEAN COMMENT 'Whether customer would recommend service',
    CONSTRAINT pk_csat_survey PRIMARY KEY(`csat_survey_id`)
) COMMENT 'Customer satisfaction survey responses for support quality measurement and churn prediction';

